// capture-events drives each registered runtime with a single prompt and
// records every raw stdout line as a JSONL snapshot under the runtime's
// testdata directory. The snapshots are intended to be consumed by the
// per-runtime parser tests so the parser is exercised against real CLI
// output, not just hand-written fixtures.
package main

import (
	"bufio"
	"context"
	"encoding/json"
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/git-hulk/cula/internal/runtime/claudecode"
	"github.com/git-hulk/cula/internal/runtime/codex"
	"github.com/git-hulk/cula/internal/runtime/opencode"
	cula "github.com/git-hulk/cula/pkg"
)

const defaultPrompt = "Read and summary this repository"

func main() {
	var (
		runtimeFlag = flag.String("runtime", "all", "runtime to capture: claude-code, codex, opencode, or all")
		prompt      = flag.String("prompt", defaultPrompt, "prompt to send to the runtime")
		workdir     = flag.String("workdir", "", "working directory for the session (defaults to repo root)")
		outDir      = flag.String("outdir", "", "override output directory (defaults to internal/runtime/<runtime>/testdata)")
		timeout     = flag.Duration("timeout", 5*time.Minute, "max time to wait for a session to finish")
		name        = flag.String("name", "summary_repo", "snapshot file basename (without extension)")
	)
	flag.Parse()

	cwd := *workdir
	if cwd == "" {
		repo, err := repoRoot()
		if err != nil {
			die("locate repo root: %v", err)
		}
		cwd = repo
	}

	targets := selectRuntimes(*runtimeFlag)
	if len(targets) == 0 {
		die("no runtimes selected for %q", *runtimeFlag)
	}

	for _, t := range targets {
		fmt.Printf("==> capturing %s\n", t.kind)
		dir := *outDir
		if dir == "" {
			repo, err := repoRoot()
			if err != nil {
				die("locate repo root: %v", err)
			}
			dir = filepath.Join(repo, "internal", "runtime", t.dir, "testdata")
		}
		if err := os.MkdirAll(dir, 0o755); err != nil {
			die("mkdir %s: %v", dir, err)
		}
		path := filepath.Join(dir, *name+".jsonl")
		if err := capture(t, *prompt, cwd, path, *timeout); err != nil {
			die("capture %s: %v", t.kind, err)
		}
		fmt.Printf("    wrote %s\n", path)
	}
}

type target struct {
	kind cula.RuntimeKind
	dir  string
	new  func() cula.Runtime
}

func selectRuntimes(name string) []target {
	all := []target{
		{cula.RuntimeClaudeCode, "claudecode", func() cula.Runtime { return claudecode.New(cula.Config{}) }},
		{cula.RuntimeCodex, "codex", func() cula.Runtime { return codex.New(cula.Config{}) }},
		{cula.RuntimeOpenCode, "opencode", func() cula.Runtime { return opencode.New(cula.Config{}) }},
	}
	if name == "all" || name == "" {
		return all
	}
	for _, t := range all {
		if string(t.kind) == name || t.dir == name {
			return []target{t}
		}
	}
	return nil
}

func capture(t target, prompt, cwd, outPath string, timeout time.Duration) error {
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	rt := t.new()
	session, err := rt.SpawnSession(ctx, cula.SessionInput{
		Runtime:    t.kind,
		Prompt:     prompt,
		WorkingDir: cwd,
	})
	if err != nil {
		return fmt.Errorf("spawn session: %w", err)
	}
	defer session.Cancel(context.Background())

	f, err := os.Create(outPath)
	if err != nil {
		return fmt.Errorf("create %s: %w", outPath, err)
	}
	defer f.Close()
	w := bufio.NewWriter(f)
	defer w.Flush()

	count := 0
	for ev := range session.Events() {
		if len(ev.Raw) == 0 {
			// Synthetic events (state, done) without a raw line don't belong in
			// the snapshot — they aren't produced by the parser.
			continue
		}
		// Re-marshal Raw as a single line to guarantee one event per line.
		compact, err := compactJSON(ev.Raw)
		if err != nil {
			return fmt.Errorf("compact raw line: %w", err)
		}
		if _, err := w.Write(compact); err != nil {
			return err
		}
		if err := w.WriteByte('\n'); err != nil {
			return err
		}
		count++
		if isTerminal(ev) {
			break
		}
	}
	fmt.Printf("    captured %d raw events\n", count)
	if count == 0 {
		return fmt.Errorf("no raw events captured (is the CLI authenticated?)")
	}
	return nil
}

func isTerminal(ev cula.Event) bool {
	switch ev.Type {
	case cula.EventState:
		return ev.State == cula.StateCompleted || ev.State == cula.StateFailed || ev.State == cula.StateCanceled
	case cula.EventDone:
		return true
	}
	return false
}

func compactJSON(raw json.RawMessage) ([]byte, error) {
	var v any
	if err := json.Unmarshal(raw, &v); err != nil {
		return nil, err
	}
	return json.Marshal(v)
}

func repoRoot() (string, error) {
	wd, err := os.Getwd()
	if err != nil {
		return "", err
	}
	dir := wd
	for {
		if _, err := os.Stat(filepath.Join(dir, "go.mod")); err == nil {
			return dir, nil
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			return "", fmt.Errorf("go.mod not found above %s", wd)
		}
		dir = parent
	}
}

func die(format string, args ...any) {
	if !strings.HasSuffix(format, "\n") {
		format += "\n"
	}
	fmt.Fprintf(os.Stderr, format, args...)
	os.Exit(1)
}
